//! Benchmark: Standing Wave Audio Entropy for FOIL
//!
//! Generates synthetic audio with known standing waves (pink noise + tones
//! at golden ratio harmonics), runs the full pipeline (DFT + amplituhedron
//! filter + FOIL admission), and reports throughput/latency/admission rate.
//!
//! ```text
//! cargo build --manifest-path open-source/gnosis/distributed-inference/Cargo.toml \
//!   --features "spectrum-waterfall" --bin bench-standing-wave-entropy --release
//! ```

use distributed_inference::gnosis_foil::{
    foil_entropy_boost_standing_wave, foil_standing_wave_entropy_telemetry,
};
use distributed_inference::standing_wave_entropy::{
    StandingWaveDFT, STANDING_WAVE_HOP, STANDING_WAVE_N_FFT,
};
use std::time::Instant;

const SAMPLE_RATE: usize = 16_000;
const GOLDEN_RATIO: f32 = 1.618_033_9;

fn generate_pink_noise(n: usize, seed: u64) -> Vec<f32> {
    let mut samples = Vec::with_capacity(n);
    let mut state = [0.0f32; 7];
    let mut rng = seed;
    for _ in 0..n {
        rng = rng
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let white = (rng as f32 / u64::MAX as f32) * 2.0 - 1.0;
        state[0] = 0.99886 * state[0] + white * 0.0555179;
        state[1] = 0.99332 * state[1] + white * 0.0750759;
        state[2] = 0.96900 * state[2] + white * 0.1538520;
        state[3] = 0.86650 * state[3] + white * 0.3104856;
        state[4] = 0.55000 * state[4] + white * 0.5329522;
        state[5] = -0.7616 * state[5] - white * 0.0168980;
        let pink = state[0]
            + state[1]
            + state[2]
            + state[3]
            + state[4]
            + state[5]
            + state[6]
            + white * 0.5362;
        state[6] = white * 0.115926;
        samples.push(pink * 0.11);
    }
    samples
}

fn add_golden_tones(samples: &mut [f32], base_freq: f32) {
    let n = samples.len();
    for i in 0..n {
        let t = i as f32 / SAMPLE_RATE as f32;
        let f1 = base_freq;
        let f2 = base_freq * GOLDEN_RATIO;
        let f3 = base_freq * GOLDEN_RATIO * GOLDEN_RATIO;
        samples[i] += 0.3 * (std::f32::consts::TAU * f1 * t).sin();
        samples[i] += 0.2 * (std::f32::consts::TAU * f2 * t).sin();
        samples[i] += 0.1 * (std::f32::consts::TAU * f3 * t).sin();
    }
}

fn main() {
    let durations_s = [1.0, 5.0, 28.0];
    let base_freqs = [110.0, 440.0, 1000.0];

    println!("STANDING WAVE ENTROPY BENCHMARK");
    println!("================================");
    println!("Pipeline: PCM -> DFT (nFft=2048, hop=512) -> amplituhedron (10 deaths) -> FOIL keys");
    println!();

    for &dur in &durations_s {
        let n_samples = (dur * SAMPLE_RATE as f32) as usize;
        let n_windows = if n_samples >= STANDING_WAVE_N_FFT {
            (n_samples - STANDING_WAVE_N_FFT) / STANDING_WAVE_HOP + 1
        } else {
            0
        };

        println!(
            "--- Duration: {:.1}s ({} samples, {} windows) ---",
            dur, n_samples, n_windows
        );

        for &base_freq in &base_freqs {
            let mut samples = generate_pink_noise(n_samples, (base_freq * 1000.0) as u64);
            add_golden_tones(&mut samples, base_freq);

            let dft = StandingWaveDFT::new();

            // Benchmark: full analysis
            let t0 = Instant::now();
            let analysis = dft.analyze(&samples);
            let analysis_us = t0.elapsed().as_micros();

            // Benchmark: FOIL admission
            let peaks: Vec<(u16, f32)> = analysis
                .surviving_indices
                .iter()
                .map(|&i| {
                    let w = &analysis.windows[i];
                    (w.dominant_bin, w.concentration)
                })
                .collect();

            let t1 = Instant::now();
            let admitted = foil_entropy_boost_standing_wave(&peaks, analysis_us as u64 * 1000);
            let foil_us = t1.elapsed().as_micros();

            let (total_admitted, total_dropped) = foil_standing_wave_entropy_telemetry();
            let survived = analysis.surviving_indices.len();
            let admission_rate = if peaks.len() > 0 {
                admitted as f64 / peaks.len() as f64 * 100.0
            } else {
                0.0
            };

            let throughput_windows_per_ms = if analysis_us > 0 {
                n_windows as f64 / (analysis_us as f64 / 1000.0)
            } else {
                0.0
            };

            println!(
                "  base={:>4.0}Hz | analysis: {:>6}us ({:.0} win/ms) | survived: {:>3}/{} ({:.1}%) | FOIL: admitted={} ({:.0}%) in {}us",
                base_freq,
                analysis_us,
                throughput_windows_per_ms,
                survived,
                n_windows,
                if n_windows > 0 { survived as f64 / n_windows as f64 * 100.0 } else { 0.0 },
                admitted,
                admission_rate,
                foil_us,
            );

            if dur == 28.0 {
                println!(
                    "    entropy pulse: {:?}",
                    analysis.entropy_pulse_period_s.map(|p| format!(
                        "{:.3}s ({:.1}Hz)",
                        p,
                        1.0 / p
                    ))
                );
                println!(
                    "    noise: W={} P={} B={} S={}",
                    analysis.noise_histogram[0],
                    analysis.noise_histogram[1],
                    analysis.noise_histogram[2],
                    analysis.noise_histogram[3]
                );
                println!("    death layers: {:?}", analysis.death_stats);
                println!(
                    "    keys harvested: {} (max {})",
                    analysis.entropy_keys.len(),
                    199
                );
                if let Some(ref tri) = analysis.tri_channel {
                    println!(
                        "    tri-channel: Fork={} Race={} Fold={} (total={})",
                        tri.fork_keys.len(),
                        tri.race_keys.len(),
                        tri.fold_keys.len(),
                        tri.fork_keys.len() + tri.race_keys.len() + tri.fold_keys.len()
                    );
                    println!(
                        "    dominant bins: Fork={} Race={} Fold={}",
                        tri.fork_dominant_bin, tri.race_dominant_bin, tri.fold_dominant_bin
                    );
                }
            }
        }
        println!();
    }

    let (final_admitted, final_dropped) = foil_standing_wave_entropy_telemetry();
    println!(
        "TOTALS: admitted={}, dropped={}, admission_rate={:.1}%",
        final_admitted,
        final_dropped,
        if final_admitted + final_dropped > 0 {
            final_admitted as f64 / (final_admitted + final_dropped) as f64 * 100.0
        } else {
            0.0
        }
    );
}
